UPDATE wms_inbound_order
SET order_status = CASE WHEN order_status = 0 THEN 1 ELSE order_status END,
    update_by = #{operator}
WHERE id = #{orderId}
  AND dr = 0

UPDATE wms_inventory
SET quantity = quantity + #{delta},
    available_quantity = available_quantity + #{delta},
    last_inbound_time = #{inboundTime},
    update_by = #{operator}
WHERE id = #{id}

UPDATE wms_inbound_order
SET actual_quantity = actual_quantity + #{quantity},
    actual_time = #{actualTime},
    update_by = #{operator}
WHERE id = #{orderId}
  AND dr = 0
